@namespace Lumeo
@implements IAsyncDisposable

<div id="@_handleId"
     role="separator"
     tabindex="0"
     class="@CssClass"
     data-panel-group-direction="@DirectionString"
     @attributes="AdditionalAttributes">
    @if (WithHandle)
    {
        @if (Context.Direction == ResizablePanelGroup.ResizableDirection.Horizontal)
        {
            <div class="z-10 flex h-4 w-3 items-center justify-center rounded-sm border bg-border">
                <Blazicon Svg="Lucide.GripVertical" class="h-2.5 w-2.5" />
            </div>
        }
        else
        {
            <div class="z-10 flex h-3 w-4 items-center justify-center rounded-sm border bg-border">
                <Blazicon Svg="Lucide.GripHorizontal" class="h-2.5 w-2.5" />
            </div>
        }
    }
</div>

@inject ComponentInteropService Interop

@code {
    [CascadingParameter] public ResizablePanelGroup.ResizablePanelGroupContext Context { get; set; } = default!;
    [Parameter, EditorRequired] public int PanelIndex { get; set; }
    [Parameter] public bool WithHandle { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _handleId = $"resizable-handle-{Guid.NewGuid():N}";

    private string DirectionString =>
        Context.Direction == ResizablePanelGroup.ResizableDirection.Horizontal ? "horizontal" : "vertical";

    private string CssClass =>
        Context.Direction == ResizablePanelGroup.ResizableDirection.Horizontal
            ? $"relative flex w-px items-center justify-center bg-border after:absolute after:inset-y-0 after:-left-1 after:-right-1 after:content-[''] hover:bg-primary/50 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring focus-visible:ring-offset-1 cursor-col-resize {Class}".Trim()
            : $"relative flex h-px w-full items-center justify-center bg-border after:absolute after:inset-x-0 after:-top-1 after:-bottom-1 after:content-[''] hover:bg-primary/50 focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring focus-visible:ring-offset-1 cursor-row-resize {Class}".Trim();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            var direction = Context.Direction == ResizablePanelGroup.ResizableDirection.Horizontal
                ? "horizontal"
                : "vertical";

            await Interop.RegisterResizeHandle(
                _handleId,
                direction,
                async (delta) =>
                {
                    await Context.OnHandleDrag.InvokeAsync((PanelIndex, delta));
                },
                async () =>
                {
                    await InvokeAsync(StateHasChanged);
                }
            );
        }
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            await Interop.UnregisterResizeHandle(_handleId);
        }
        catch (JSDisconnectedException) { }
    }
}

@namespace Lumeo

<div class="@CssClass"
     style="flex: @(Size.ToString("F2", System.Globalization.CultureInfo.InvariantCulture)) 1 0; min-width: 0; min-height: 0; overflow: auto;"
     @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public ResizablePanelGroup.ResizablePanelGroupContext Context { get; set; } = default!;
    [Parameter] public int Order { get; set; }
    [Parameter] public double DefaultSize { get; set; } = 50;
    [Parameter] public double MinSize { get; set; } = 10;
    [Parameter] public double MaxSize { get; set; } = 90;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private double Size => Context?.GetPanelSize(Order) ?? DefaultSize;

    private string CssClass => $"relative {Class}".Trim();

    protected override void OnInitialized()
    {
        Context?.RegisterPanel?.Invoke(Order, MinSize, MaxSize);
    }
}

@namespace Lumeo
@implements IAsyncDisposable

@{
    var context = new ResizablePanelGroupContext(
        _groupId,
        Direction,
        EventCallback.Factory.Create<(int PanelIndex, double Delta)>(this, HandleDrag),
        GetPanelSize,
        _sizes.Count,
        RegisterPanel
    );
}

<div id="@_groupId"
     class="@CssClass"
     data-panel-group-direction="@DirectionString"
     @attributes="AdditionalAttributes">
    <CascadingValue Value="context" IsFixed="false">
        @ChildContent
    </CascadingValue>
</div>

@inject ComponentInteropService Interop

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public ResizableDirection Direction { get; set; } = ResizableDirection.Horizontal;
    [Parameter] public double[]? DefaultSizes { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _groupId = $"resizable-group-{Guid.NewGuid():N}";
    private List<double> _sizes = new();
    private int _panelCount;
    private readonly Dictionary<int, (double MinSize, double MaxSize)> _panelConstraints = new();

    private string DirectionString => Direction == ResizableDirection.Horizontal ? "horizontal" : "vertical";

    private string CssClass =>
        Direction == ResizableDirection.Horizontal
            ? $"flex h-full w-full {Class}".Trim()
            : $"flex h-full w-full flex-col {Class}".Trim();

    protected override void OnParametersSet()
    {
        if (DefaultSizes is { Length: > 0 })
        {
            if (_sizes.Count != DefaultSizes.Length)
            {
                _sizes = new List<double>(DefaultSizes);
                _panelCount = DefaultSizes.Length;
            }
        }
    }

    private double GetPanelSize(int index)
    {
        if (index >= 0 && index < _sizes.Count)
        {
            return _sizes[index];
        }

        // Fallback: equal distribution
        var count = _panelCount > 0 ? _panelCount : 1;
        return 100.0 / count;
    }

    private void RegisterPanel(int order, double minSize, double maxSize)
    {
        _panelConstraints[order] = (minSize, maxSize);
    }

    private async Task HandleDrag((int PanelIndex, double Delta) args)
    {
        var (panelIndex, deltaPx) = args;

        if (panelIndex < 0 || panelIndex + 1 >= _sizes.Count)
            return;

        // Convert delta from pixels to percentage of total group dimension
        var dimension = Direction == ResizableDirection.Horizontal ? "width" : "height";
        var totalSize = await Interop.GetElementDimension(_groupId, dimension);

        if (totalSize <= 0)
            return;

        var deltaPercent = (deltaPx / totalSize) * 100.0;

        var newLeft = _sizes[panelIndex] + deltaPercent;
        var newRight = _sizes[panelIndex + 1] - deltaPercent;

        // Enforce per-panel min/max constraints
        var leftConstraints = _panelConstraints.TryGetValue(panelIndex, out var lc) ? lc : (MinSize: 0.0, MaxSize: 100.0);
        var rightConstraints = _panelConstraints.TryGetValue(panelIndex + 1, out var rc) ? rc : (MinSize: 0.0, MaxSize: 100.0);

        if (newLeft < leftConstraints.MinSize || newLeft > leftConstraints.MaxSize) return;
        if (newRight < rightConstraints.MinSize || newRight > rightConstraints.MaxSize) return;

        _sizes[panelIndex] = newLeft;
        _sizes[panelIndex + 1] = newRight;

        StateHasChanged();
    }

    public ValueTask DisposeAsync()
    {
        return ValueTask.CompletedTask;
    }

    public enum ResizableDirection { Horizontal, Vertical }

    public record ResizablePanelGroupContext(
        string GroupId,
        ResizableDirection Direction,
        EventCallback<(int PanelIndex, double Delta)> OnHandleDrag,
        Func<int, double> GetPanelSize,
        int PanelCount,
        Action<int, double, double> RegisterPanel
    );
}
